package v1

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"

	"github.com/go-openapi/strfmt"
	amModels "github.com/prometheus/alertmanager/api/v2/models"
)

// SilenceCreator creates a single alertmanager silence and returns its assigned ID.
type SilenceCreator interface {
	CreateSilence(ctx context.Context, ps *amModels.PostableSilence) (string, error)
}

// BulkSilenceResult is the per-item outcome of a bulk silence creation request.
// Exactly one of SilenceID or Error will be non-empty.
type BulkSilenceResult struct {
	SilenceID string `json:"silenceId,omitempty"`
	Error     string `json:"error,omitempty"`
}

// createBulkSilences handles POST /api/v1/silences/bulk.
// It accepts a JSON array of PostableSilence objects and attempts to create each one.
// Results are returned per-item so callers can distinguish partial failures.
func (api *API) createBulkSilences(r *http.Request) apiFuncResult {
	if api.silenceCreator == nil {
		return apiFuncResult{nil, &apiError{errorInternal, errors.New("silence creation not configured")}, nil, nil}
	}

	var silences []*amModels.PostableSilence
	if err := json.NewDecoder(r.Body).Decode(&silences); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid request body: %w", err)}, nil, nil}
	}

	if len(silences) == 0 {
		return apiFuncResult{nil, &apiError{errorBadData, errors.New("request must contain at least one silence")}, nil, nil}
	}

	results := make([]BulkSilenceResult, len(silences))
	for i, s := range silences {
		if err := s.Validate(strfmt.Default); err != nil {
			results[i] = BulkSilenceResult{Error: fmt.Sprintf("silence %d validation failed: %s", i, err)}
			continue
		}
		id, err := api.silenceCreator.CreateSilence(r.Context(), s)
		if err != nil {
			results[i] = BulkSilenceResult{Error: fmt.Sprintf("silence %d creation failed: %s", i, err)}
			continue
		}
		results[i] = BulkSilenceResult{SilenceID: id}
	}

	return apiFuncResult{results, nil, nil, nil}
}

