// mockSilenceCreator is a test double for SilenceCreator.
// errOn maps a zero-based silence index to the error it should return.
// nextID is the sequence used to generate auto-incrementing IDs.
type mockSilenceCreator struct {
	errOn  map[int]error
	nextID int
	calls  []*amModels.PostableSilence
}

func (m *mockSilenceCreator) CreateSilence(_ context.Context, ps *amModels.PostableSilence) (string, error) {
	idx := len(m.calls)
	m.calls = append(m.calls, ps)
	if err, ok := m.errOn[idx]; ok {
		return "", err
	}
	m.nextID++
	return strconv.AppendInt(nil, int64(m.nextID), 10), nil // e.g. "1", "2", …
}

// newMockSilenceCreator returns a fresh mockSilenceCreator whose CreateSilence
// will fail for the call indices listed in failAt.
func newMockSilenceCreator(failAt map[int]error) *mockSilenceCreator {
	return &mockSilenceCreator{errOn: failAt}
}

// silencePayload builds a minimal valid PostableSilence for use in tests.
func silencePayload(alertname string) *amModels.PostableSilence {
	f := false
	comment := "test silence"
	createdBy := "test-user"
	now := strfmt.DateTime(time.Now().UTC())
	later := strfmt.DateTime(time.Now().UTC().Add(time.Hour))
	return &amModels.PostableSilence{
		Silence: amModels.Silence{
			Matchers: amModels.Matchers{
				{Name: &alertname, Value: &alertname, IsRegex: &f},
			},
			StartsAt:  &now,
			EndsAt:    &later,
			Comment:   &comment,
			CreatedBy: &createdBy,
		},
	}
}

// postBulkRequest builds an *http.Request with the given body JSON posted to
// /api/v1/silences/bulk.
func postBulkRequest(t *testing.T, body any) *http.Request {
	t.Helper()
	b, err := json.Marshal(body)
	require.NoError(t, err)
	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(b))
	req.Header.Set("Content-Type", "application/json")
	return req
}

// ---- Tests ----

func TestCreateBulkSilences_NotConfigured(t *testing.T) {
	api := &API{} // silenceCreator is nil
	req := postBulkRequest(t, []*amModels.PostableSilence{silencePayload("TestAlert")})

	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorInternal, result.err.typ)
	require.Contains(t, result.err.err.Error(), "not configured")
}

func TestCreateBulkSilences_InvalidJSON(t *testing.T) {
	api := &API{silenceCreator: newMockSilenceCreator(nil)}
	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk",
		bytes.NewBufferString(`{not valid json}`))
	req.Header.Set("Content-Type", "application/json")

	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
	require.Contains(t, result.err.err.Error(), "invalid request body")
}

func TestCreateBulkSilences_EmptyArray(t *testing.T) {
	api := &API{silenceCreator: newMockSilenceCreator(nil)}
	req := postBulkRequest(t, []*amModels.PostableSilence{})

	result := api.createBulkSilences(req)

	require.NotNil(t, result.err)
	require.Equal(t, errorBadData, result.err.typ)
	require.Contains(t, result.err.err.Error(), "at least one silence")
}

func TestCreateBulkSilences_Success(t *testing.T) {
	creator := newMockSilenceCreator(nil)
	api := &API{silenceCreator: creator}

	silences := []*amModels.PostableSilence{
		silencePayload("AlertOne"),
		silencePayload("AlertTwo"),
		silencePayload("AlertThree"),
	}
	req := postBulkRequest(t, silences)

	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	results, ok := result.data.([]BulkSilenceResult)
	require.True(t, ok, "expected []BulkSilenceResult, got %T", result.data)
	require.Len(t, results, 3)

	for i, r := range results {
		require.NotEmpty(t, r.SilenceID, "result %d should have a silenceId", i)
		require.Empty(t, r.Error, "result %d should have no error", i)
	}
	// All three silences must have been forwarded to the creator.
	require.Len(t, creator.calls, 3)
}

func TestCreateBulkSilences_ValidationFailure(t *testing.T) {
	creator := newMockSilenceCreator(nil)
	api := &API{silenceCreator: creator}

	// Build an invalid silence: missing required matchers.
	invalid := &amModels.PostableSilence{} // all required fields absent

	req := postBulkRequest(t, []*amModels.PostableSilence{invalid})

	result := api.createBulkSilences(req)

	// The handler itself succeeds; per-item errors are embedded in the results.
	require.Nil(t, result.err)
	results, ok := result.data.([]BulkSilenceResult)
	require.True(t, ok)
	require.Len(t, results, 1)
	require.Empty(t, results[0].SilenceID)
	require.Contains(t, results[0].Error, "validation failed")

	// Creator must not have been called for an invalid silence.
	require.Empty(t, creator.calls)
}

func TestCreateBulkSilences_CreatorError(t *testing.T) {
	creator := newMockSilenceCreator(map[int]error{
		0: errors.New("alertmanager unreachable"),
	})
	api := &API{silenceCreator: creator}

	req := postBulkRequest(t, []*amModels.PostableSilence{silencePayload("TestAlert")})

	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	results, ok := result.data.([]BulkSilenceResult)
	require.True(t, ok)
	require.Len(t, results, 1)
	require.Empty(t, results[0].SilenceID)
	require.Contains(t, results[0].Error, "alertmanager unreachable")
}

func TestCreateBulkSilences_PartialFailure(t *testing.T) {
	// Silence at index 1 returns an error; the rest should succeed.
	creator := newMockSilenceCreator(map[int]error{
		1: errors.New("quota exceeded"),
	})
	api := &API{silenceCreator: creator}

	silences := []*amModels.PostableSilence{
		silencePayload("First"),
		silencePayload("Second"), // will fail at creator level
		silencePayload("Third"),
	}
	req := postBulkRequest(t, silences)

	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	results, ok := result.data.([]BulkSilenceResult)
	require.True(t, ok)
	require.Len(t, results, 3)

	require.NotEmpty(t, results[0].SilenceID, "first silence should succeed")
	require.Empty(t, results[0].Error)

	require.Empty(t, results[1].SilenceID, "second silence should fail")
	require.Contains(t, results[1].Error, "quota exceeded")

	require.NotEmpty(t, results[2].SilenceID, "third silence should succeed")
	require.Empty(t, results[2].Error)
}

func TestCreateBulkSilences_MixedValidAndInvalid(t *testing.T) {
	creator := newMockSilenceCreator(nil)
	api := &API{silenceCreator: creator}

	// index 0: valid, index 1: invalid (missing matchers), index 2: valid
	invalid := &amModels.PostableSilence{}
	silences := []*amModels.PostableSilence{
		silencePayload("First"),
		invalid,
		silencePayload("Third"),
	}
	req := postBulkRequest(t, silences)

	result := api.createBulkSilences(req)

	require.Nil(t, result.err)
	results, ok := result.data.([]BulkSilenceResult)
	require.True(t, ok)
	require.Len(t, results, 3)

	require.NotEmpty(t, results[0].SilenceID)
	require.Empty(t, results[0].Error)

	require.Empty(t, results[1].SilenceID)
	require.Contains(t, results[1].Error, "validation failed")

	require.NotEmpty(t, results[2].SilenceID)
	require.Empty(t, results[2].Error)

	// Creator should have been called only for the two valid silences.
	require.Len(t, creator.calls, 2)
}

// TestCreateBulkSilences_RouteRegistered verifies the endpoint is reachable
// through the router at POST /api/v1/silences/bulk.
func TestCreateBulkSilences_RouteRegistered(t *testing.T) {
	api := &API{
		silenceCreator: newMockSilenceCreator(nil),
		ready:          func(f http.HandlerFunc) http.HandlerFunc { return f },
	}
	api.InstallCodec(JSONCodec{})

	router := createPrometheusAPIRouter(t, api)

	body, err := json.Marshal([]*amModels.PostableSilence{silencePayload("RouteTest")})
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()

	router.ServeHTTP(rec, req)

	require.Equal(t, http.StatusOK, rec.Code)

	var resp struct {
		Status string              `json:"status"`
		Data   []BulkSilenceResult `json:"data"`
	}
	require.NoError(t, json.NewDecoder(rec.Body).Decode(&resp))
	require.Equal(t, "success", resp.Status)
	require.Len(t, resp.Data, 1)
	require.NotEmpty(t, resp.Data[0].SilenceID)
}

