    30	}
    31	
    32	// BulkSilenceResult is the per-item outcome of a bulk silence creation request.
    33	// Exactly one of SilenceID or Error will be non-empty.
    34	type BulkSilenceResult struct {
    35		SilenceID string `json:"silenceId,omitempty"`
    36		Error     string `json:"error,omitempty"`
    37	}
    38	
    39	// createBulkSilences handles POST /api/v1/silences/bulk.
    40	// It accepts a JSON array of PostableSilence objects and attempts to create each one.
    41	// Results are returned per-item so callers can distinguish partial failures.
    42	func (api *API) createBulkSilences(r *http.Request) apiFuncResult {
    43		if api.silenceCreator == nil {
    44			return apiFuncResult{nil, &apiError{errorInternal, errors.New("silence creation not configured")}, nil, nil}
    45		}
    46	
    47		var silences []*amModels.PostableSilence
    48		if err := json.NewDecoder(r.Body).Decode(&silences); err != nil {
    49			return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid request body: %w", err)}, nil, nil}
    50		}
