    63			if err != nil {
    64				results[i] = BulkSilenceResult{Error: fmt.Sprintf("silence %d creation failed: %s", i, err)}
    65				continue
    66			}
    67			results[i] = BulkSilenceResult{SilenceID: id}
    68		}
